function heatMacroCommand() {
  return String.raw`const macroArgs = typeof args !== "undefined" ? args : [];
const data = macroArgs?.[0] ?? {};
const workflow = data.workflow ?? globalThis.workflow;
if (!workflow || data.macroPass !== "isDamaged") return;

function num(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function actorFromDocument(documentOrActor) {
  if (!documentOrActor) return null;
  if (documentOrActor.actor) return documentOrActor.actor;
  return documentOrActor;
}

function tokenObjectFromDocument(documentOrToken) {
  if (!documentOrToken) return null;
  if (documentOrToken.object) return documentOrToken.object;
  if (documentOrToken.document) return documentOrToken;
  return null;
}

async function resolveUuid(uuid) {
  if (!uuid) return null;
  try {
    return await fromUuid(uuid);
  } catch (_error) {
    return null;
  }
}

function centerOf(tokenLike) {
  const tokenDoc = tokenLike?.document ?? tokenLike;
  return tokenLike?.center ?? {
    x: num(tokenDoc?.x) + num(tokenDoc?.width, 1) * (canvas.grid?.size ?? 100) / 2,
    y: num(tokenDoc?.y) + num(tokenDoc?.height, 1) * (canvas.grid?.size ?? 100) / 2
  };
}

function distanceFt(a, b) {
  try {
    if (globalThis.MidiQOL?.computeDistance) return MidiQOL.computeDistance(a, b, { wallsBlock: false, includeCover: false });
  } catch (_error) {}
  const ac = centerOf(a);
  const bc = centerOf(b);
  const gridSize = canvas.grid?.size ?? canvas.scene?.grid?.size ?? 100;
  const gridDistance = canvas.dimensions?.distance ?? canvas.scene?.grid?.distance ?? 5;
  return Math.hypot(ac.x - bc.x, ac.y - bc.y) / gridSize * gridDistance;
}

function getTargetUuids(selfActor, selfToken) {
  const uuids = new Set();
  if (selfToken?.document?.uuid) uuids.add(selfToken.document.uuid);
  if (selfToken?.actor?.uuid) uuids.add(selfToken.actor.uuid);
  if (selfActor?.uuid) uuids.add(selfActor.uuid);
  return uuids;
}

function workflowDamagedSelf(workflow, selfActor, selfToken) {
  const targetUuids = getTargetUuids(selfActor, selfToken);
  const list = workflow.damageList ?? [];
  return list.some(entry => {
    const damaged = num(entry.hpDamage) > 0 || num(entry.tempDamage) > 0 || num(entry.oldHP) > num(entry.newHP);
    if (!damaged) return false;
    return targetUuids.has(entry.targetUuid) || targetUuids.has(entry.actorUuid) || entry.actorId === selfActor?.id || entry.tokenId === selfToken?.id;
  });
}

function isMeleeAttack(workflow) {
  const attack = workflow.activity?.attack;
  if (attack?.type?.value === "melee") return true;
  const actionType = workflow.item?.system?.actionType ?? workflow.item?.system?.type?.value ?? "";
  return ["mwak", "msak"].includes(actionType);
}

async function playHeatFx(target) {
  try {
    if (!globalThis.Sequence) return;
    new Sequence()
      .effect()
      .file("modules/jb2a_patreon/Library/Generic/Fire/FireBurst_01_Regular_Orange_400x400.webm")
      .atLocation(target)
      .scaleToObject(1.2)
      .fadeIn(100)
      .fadeOut(250)
      .play();
  } catch (error) {
    console.warn("SewerRemorhazHeatBody animation failed", error);
  }
}

async function applyHeatDamage(selfActor, selfToken, attackerToken, heatItem, dice) {
  const formula = String(dice) + "d6";
  const roll = await new Roll(formula).evaluate();
  await roll.toMessage({
    speaker: ChatMessage.getSpeaker({ actor: selfActor, token: selfToken?.document ?? selfToken }),
    flavor: "<strong>Раскалённое тело.</strong> " + attackerToken.name + " обжигается о раскалённый панцирь ремораза."
  });
  const itemDoc = heatItem ?? { name: "Раскалённое тело", img: "icons/magic/fire/flame-burning-creature-skeleton.webp", actor: selfActor };
  const detail = [{ damage: roll.total, value: roll.total, type: "fire", formula, properties: new Set(["mgc", "damage"]) }];
  try {
    if (globalThis.MidiQOL?.applyTokenDamage) {
      await MidiQOL.applyTokenDamage(detail, roll.total, new Set([attackerToken]), itemDoc, new Set(), {
        existingDamage: [],
        workflowOptions: { sourceToken: selfToken, flavor: "Раскалённое тело" }
      });
    } else {
      const hp = attackerToken.actor?.system?.attributes?.hp;
      const next = Math.max(0, num(hp?.value) - roll.total);
      await attackerToken.actor?.update({ "system.attributes.hp.value": next });
    }
  } catch (error) {
    console.error("SewerRemorhazHeatBody damage failed", error);
    ui.notifications?.error("Раскалённое тело: не удалось применить урон, подробности в консоли.");
  }
}

if (workflow.item?.flags?.world?.sewerRemorhazHeatBody) return;

const selfActor = actorFromDocument(actor) ?? workflow.actor;
let selfToken = tokenObjectFromDocument(data.options?.token) ?? tokenObjectFromDocument(token);
if (!selfToken && selfActor) selfToken = canvas.tokens?.placeables?.find(t => t.actor?.id === selfActor.id) ?? null;

const attackerResolved = tokenObjectFromDocument(workflow.token)
  ?? tokenObjectFromDocument(await resolveUuid(workflow.tokenUuid))
  ?? canvas.tokens?.placeables?.find(t => t.id === workflow.tokenId || t.document?.uuid === workflow.tokenUuid)
  ?? null;

if (!selfActor || !selfToken || !attackerResolved) return;
if (attackerResolved.id === selfToken.id) return;
if (!isMeleeAttack(workflow)) return;
if (!workflowDamagedSelf(workflow, selfActor, selfToken)) return;
if (distanceFt(attackerResolved, selfToken) > 5) return;

const heatItem = selfActor.items?.find(item => item.flags?.world?.sewerRemorhazHeatBody || item.name === "Раскалённое тело") ?? null;
const dice = Math.max(1, num(heatItem?.flags?.world?.sewerRemorhazHeatDice ?? selfActor.getFlag?.("world", "sewerRemorhazHeatDice"), 2));
const key = [
  workflow.id ?? workflow.uuid ?? workflow.itemCardUuid ?? game.time.worldTime,
  selfToken.document?.uuid ?? selfToken.id,
  attackerResolved.document?.uuid ?? attackerResolved.id,
  dice
].join("|");
if (selfActor.getFlag?.("world", "sewerRemorhazHeatBodyLastWorkflow") === key) return;
await selfActor.setFlag?.("world", "sewerRemorhazHeatBodyLastWorkflow", key);

await playHeatFx(attackerResolved);
await applyHeatDamage(selfActor, selfToken, attackerResolved, heatItem, dice);`;
}

function duplicate(value) {
  return foundry.utils.deepClone(value ?? {});
}

function hasMacroRef(flags, macroName) {
  const raw = flags?.["midi-qol"]?.onUseMacroName ?? "";
  return String(raw).includes(macroName);
}

function normalizeMidiMacroFlags(document, macroNames) {
  const flags = duplicate(document.flags);
  flags["midi-qol"] ??= {};
  const midi = flags["midi-qol"];
  const parts = [];

  for (const part of midi.onUseMacroParts?.items ?? []) {
    const option = part.option ?? "postActiveEffects";
    let macroName = String(part.macroName ?? "").trim();
    if (!macroName) continue;
    if (macroName === OLD_ENGINE_MACRO_NAME) macroName = ENGINE_MACRO_NAME;
    if (macroName === "Sewer Remorhaz Heat Body") macroName = HEAT_MACRO_NAME;
    const key = `${option}|${macroName}`;
    if (!parts.some(existing => `${existing.option}|${existing.macroName}` === key)) parts.push({ option, macroName });
  }

  for (const chunk of String(midi.onUseMacroName ?? "").split(",").map(s => s.trim()).filter(Boolean)) {
    const match = chunk.match(/^\[([^\]]+)\](.+)$/);
    const option = match ? match[1] : "postActiveEffects";
    let macroName = (match ? match[2] : chunk).trim();
    if (macroName === OLD_ENGINE_MACRO_NAME) macroName = ENGINE_MACRO_NAME;
    if (macroName === "Sewer Remorhaz Heat Body") macroName = HEAT_MACRO_NAME;
    const key = `${option}|${macroName}`;
    if (!parts.some(existing => `${existing.option}|${existing.macroName}` === key)) parts.push({ option, macroName });
  }

  for (const macroName of macroNames) {
    const option = "isDamaged";
    const key = `${option}|${macroName}`;
    if (!parts.some(existing => `${existing.option}|${existing.macroName}` === key)) parts.push({ option, macroName });
  }

  midi.onUseMacroParts = { items: parts };
  midi.onUseMacroName = parts.map(part => `[${part.option}]${part.macroName}`).join(",");
  return flags;
}

