function classifyActor(actor) {
  return TARGETS.find(target => target.exactIds.includes(actor.id)) ?? TARGETS.find(target => target.name(actor)) ?? null;
}

async function upsertMacro({ dryRun, log }) {
  const command = heatMacroCommand();
  const existing = game.macros.find(macro => macro.name === HEAT_MACRO_NAME);
  if (dryRun) {
    return existing ? { update: existing.name } : { create: HEAT_MACRO_NAME };
  }
  if (existing) {
    await existing.update({ type: "script", scope: "global", img: ICON, command, "flags.world.sewerRemorhazHeatBody": true });
    log(`Обновлён макрос ${HEAT_MACRO_NAME}`);
    return { updated: existing.uuid };
  }
  const created = await Macro.create({
    name: HEAT_MACRO_NAME,
    type: "script",
    scope: "global",
    img: ICON,
    command,
    ownership: { default: CONST.DOCUMENT_OWNERSHIP_LEVELS.OWNER },
    flags: { world: { sewerRemorhazHeatBody: true } }
  });
  log(`Создан макрос ${HEAT_MACRO_NAME}`);
  return { created: created.uuid };
}

async function patchActor(actor, target, { dryRun, log, label }) {
  const neededMacros = target.kind === "adult" ? [ENGINE_MACRO_NAME, HEAT_MACRO_NAME] : [HEAT_MACRO_NAME];
  const flags = normalizeMidiMacroFlags(actor, neededMacros);
  const itemData = heatItemData(actor, target);
  const existingItem = actor.items.find(item => item.flags?.world?.sewerRemorhazHeatBody || item.name === "Раскалённое тело");
  const operations = {
    actor: actor.name,
    label,
    dice: target.dice,
    macroBefore: actor.flags?.["midi-qol"]?.onUseMacroName ?? "",
    macroAfter: flags["midi-qol"].onUseMacroName,
    item: existingItem ? "update" : "create"
  };

  if (dryRun) return operations;

  await actor.update({
    flags,
    "flags.codex.sewerRemorhaz": true,
    "flags.world.sewerRemorhazHeatBody": true,
    "flags.world.sewerRemorhazHeatDice": target.dice
  });
  if (existingItem) await existingItem.update({ ...itemData, _id: existingItem.id });
  else await actor.createEmbeddedDocuments("Item", [itemData], { keepId: true });
  log(`${actor.name}: ${target.dice}d6 Раскалённое тело добавлено/обновлено (${label})`);
  return operations;
}

function collectBaseActors() {
  const targets = [];
  for (const actor of game.actors.contents) {
    const target = classifyActor(actor);
    if (target) targets.push({ actor, target, label: "actor" });
  }
  return targets;
}

function collectSyntheticActors() {
  const targets = [];
  const seen = new Set();
  for (const scene of game.scenes.contents) {
    for (const tokenDoc of scene.tokens.contents) {
      if (tokenDoc.actorLink) continue;
      const target = TARGETS.find(t => t.exactIds.includes(tokenDoc.actorId)) ?? (tokenDoc.actor ? classifyActor(tokenDoc.actor) : null);
      if (!target || !tokenDoc.actor) continue;
      const key = tokenDoc.actor.uuid;
      if (seen.has(key)) continue;
      seen.add(key);
      targets.push({ actor: tokenDoc.actor, target, label: `synthetic token: ${scene.name} / ${tokenDoc.name}` });
    }
  }
  return targets;
}

export default async function patch(context = {}) {
  const { dryRun = false, log = console.log } = context;
  if (game.system.id !== "dnd5e") throw new Error("Патч рассчитан на D&D 5e / dnd5e.");

  const macro = await upsertMacro({ dryRun, log });
  const baseActors = collectBaseActors();
  const syntheticActors = collectSyntheticActors();
  const allTargets = [...baseActors, ...syntheticActors];

  if (!allTargets.length) {
    throw new Error("Не нашёл канализационного ремораза или молодого канализационного ремораза в текущем мире.");
  }

  const changed = [];
  for (const entry of allTargets) {
    changed.push(await patchActor(entry.actor, entry.target, { dryRun, log, label: entry.label }));
  }

  return {
    ok: true,
    dryRun,
    macro,
    changed,
    summary: dryRun
      ? `Будет обновлено сущностей: ${changed.length}`
      : `Обновлено сущностей: ${changed.length}`
  };
}
